import SignUp from './pages/SignUp'; // Pastikan S dan U besar jika nama filenya SignUp.js

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/dashboard" element={<Dashboard />} />
        {/* Pastikan element-nya tertulis <SignUp /> (pakai kurung siku) */}
        <Route path="/register" element={<SignUp />} /> 
      </Routes>
    </Router>
  );
}
